import React from "react";
import { Link } from "gatsby";

/**
 * Format a date string (YYYY-MM-DD or ISO timestamp) into client-local time.
 * Falls back to the raw string if parsing fails.
 */
function formatLocalDate(dateStr) {
  if (!dateStr) return "—";
  try {
    // If it's just a date (YYYY-MM-DD), parse as UTC midnight
    const iso = dateStr.includes("T") ? dateStr : `${dateStr}T00:00:00Z`;
    const d = new Date(iso);
    if (isNaN(d.getTime())) return dateStr;

    const now = new Date();
    const isToday = d.toDateString() === now.toDateString();
    const yesterday = new Date(now);
    yesterday.setDate(yesterday.getDate() - 1);
    const isYesterday = d.toDateString() === yesterday.toDateString();

    const timeStr = d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit", hour12: false });

    if (isToday) return `Today ${timeStr}`;
    if (isYesterday) return `Yesterday ${timeStr}`;

    return d.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
    }) + ` ${timeStr}`;
  } catch {
    return dateStr;
  }
}

const ReportCard = ({ slug, category, date, sortTimestamp, title, excerpt, icon, color, lang }) => (
  <Link to={`/${lang || "vi"}${slug}`} className="report-card" style={{ borderLeftColor: color }}>
    <div className="report-card-header">
      <span className="report-card-icon">{icon}</span>
      <span className="report-card-date" title={sortTimestamp || date}>{formatLocalDate(sortTimestamp || date)}</span>
    </div>
    <h3 className="report-card-title">{title}</h3>
    <p className="report-card-excerpt">{excerpt.substring(0, 120)}…</p>
    <span className="report-card-category">{category}</span>
  </Link>
);

export default ReportCard;
